// Generate portfolio case study content
const projectData = $input.item.json;

// Generate URL-friendly slug
function generateSlug(text) {
  return text
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '');
}

const slug = generateSlug(projectData.project_name);

// Generate technologies array
const technologies = projectData.technologies_used || [];
const technologiesString = Array.isArray(technologies) ? technologies.join(', ') : technologies;

// Generate case study content
const caseStudyMarkdown = `---
title: "${projectData.project_name}"
client: "${projectData.client_name || projectData.client_company}"
industry: "${projectData.industry || 'Technology'}"
serviceType: "${projectData.service_type || 'Web Development'}"
technologies: [${technologies.map(t => `"${t}"`).join(', ')}]
completedDate: "${projectData.completion_date}"
featuredImage: "${projectData.featured_image || '/images/portfolio/default.jpg'}"
slug: "${slug}"
---

# ${projectData.project_name}

## Overview

${projectData.description || 'A custom web development project delivered by Hudson Digital Solutions.'}

## Challenge

${projectData.challenge || 'The client needed a modern, scalable solution to meet their business requirements.'}

## Solution

We developed a comprehensive solution using cutting-edge technologies including ${technologiesString}.

### Key Features

${(projectData.key_features || []).map((feature, i) => `${i + 1}. ${feature}`).join('\n')}

## Technologies Used

${technologies.map(tech => `- ${tech}`).join('\n')}

## Results

${projectData.results_achieved || 'The project was delivered successfully and exceeded client expectations.'}

### Metrics

- **Duration**: ${projectData.duration_weeks} weeks
- **Team Size**: ${projectData.team_size || 3} developers
- **Budget Range**: ${projectData.budget_range || 'Custom'}

## Client Testimonial

> ${projectData.client_testimonial || 'Working with Hudson Digital Solutions was a great experience. They delivered exactly what we needed.'}
>
> — ${projectData.client_name || projectData.client_company}

## Want Similar Results?

If you're looking for a development partner who can deliver results like this, [let's talk](https://hudsondigitalsolutions.com/contact).
`;

// Generate JSON-LD structured data
const structuredData = {
  "@context": "https://schema.org",
  "@type": "CreativeWork",
  "name": projectData.project_name,
  "description": projectData.description,
  "creator": {
    "@type": "Organization",
    "name": "Hudson Digital Solutions"
  },
  "datePublished": projectData.completion_date,
  "keywords": technologies.join(', ')
};

return {
  json: {
    // Project data
    project_id: projectData.id,
    project_name: projectData.project_name,
    slug: slug,
    client_name: projectData.client_name || projectData.client_company,
    client_email: projectData.client_email,

    // Case study content
    case_study_markdown: caseStudyMarkdown,
    structured_data: JSON.stringify(structuredData, null, 2),

    // Metadata
    technologies: technologies,
    industry: projectData.industry,
    service_type: projectData.service_type,
    completion_date: projectData.completion_date,
    featured_image: projectData.featured_image,

    // File paths
    markdown_file_path: `/content/portfolio/${slug}.md`,
    portfolio_url: `https://hudsondigitalsolutions.com/portfolio/${slug}`
  }
};

